const requestedReportType = $json.body?.reportType ?? $json.reportType ?? "overall";

const reports = {
  overall: "Overall AI Report\n\nRevenue is healthy, but profit leakage is concentrated in payroll, stockout risk, and underpriced high-volume items. Prioritize critical inventory replenishment, review slower weekday staffing, and adjust Beef Pares pricing before the weekend rush.",
  inventory: "Inventory Report\n\nChicken thigh, garlic, and takeout containers are below reorder thresholds. Place replenishment orders today, confirm supplier lead times, and tighten prep variance on beef and garlic to protect margin.",
  menu: "Menu Pricing Report\n\nBeef Pares and Crispy Chicken Rice remain strong sellers, but Beef Pares is below target margin. Raise the price, reduce portion cost, or bundle with a high-margin beverage instead of discounting.",
  payroll: "Payroll Report\n\nPayroll is above the target range on slower weekdays. Trim one service slot on Monday and Tuesday afternoons, move prep earlier, and monitor closing overtime after 9:30 PM.",
  projection: "Business Projection Report\n\nNext week should improve if current revenue trend holds and leakage controls are applied. Lock supplier pricing for core proteins and rerun the projection after the next data refresh."
};

const reportType = Object.prototype.hasOwnProperty.call(reports, requestedReportType)
  ? requestedReportType
  : "overall";

return [
  {
    json: {
      success: true,
      reportType,
      generatedAt: new Date().toISOString(),
      report: reports[reportType]
    }
  }
];
